const WebSocket = require('ws');
const wss = new WebSocket.Server({ port: 8080 });

let players = {};
let units = {};

wss.on('connection', (ws) => {
    console.log('Client connected');

    ws.on('message', (message) => {
        const data = JSON.parse(message);
        const player = players[data.playerId];

        if (!player) return;

        switch (data.command) {
            case 'build':
                buildUnit(player, data.unitType, data.x, data.y);
                break;
            case 'attack':
                attackUnit(player, data.targetPlayerId, data.targetUnitId);
                break;
            case 'move':
                moveUnit(player, data.unitId, data.x, data.y);
                break;
        }
    });

    ws.on('close', () => {
        console.log('Client disconnected');
        delete players[ws.playerId];
    });
});

function buildUnit(player, unitType, x, y) {
    const unit = { type: unitType, x, y };
    units[player.id] = units[player.id] || [];
    units[player.id].push(unit);
}

function attackUnit(player, targetPlayerId, targetUnitId) {
    const playerUnits = units[targetPlayerId];
    if (playerUnits && playerUnits.length > 0) {
        const unit = playerUnits.find((unit) => unit.id === targetUnitId);
        if (unit) {
            // Simulate attack logic here
            console.log(`Player ${player.name} attacked unit ${unit.type} of player ${targetPlayerId}`);
        }
    }
}

function moveUnit(player, unitId, x, y) {
    const units = players[player.id].units;
    const unit = units.find((unit) => unit.id === unitId);
    if (unit) {
        // Simulate movement logic here
        console.log(`Player ${player.name} moved unit ${unit.type} to (${x}, ${y})`);
    }
}

wss.on('error', (err) => {
    console.error(err);
});

